+/**
+ * Pure validation functions for order operations.
+ *
+ * These validators perform input and business-rule checks without
+ * side effects or database calls. Services fetch the required data
+ * and pass it in as arguments.
+ */
+
+import type { Order, OrderItem, OrderStatus } from '../models/order.js';
+
+/**
+ * Allowed status transitions. Exported so other modules (e.g. tests)
+ * can reference the same source of truth.
+ */
+export const ORDER_STATUS_TRANSITIONS: Record<OrderStatus, OrderStatus[]> = {
+  pending: ['confirmed', 'cancelled'],
+  confirmed: ['shipped', 'cancelled'],
+  shipped: ['delivered'],
+  delivered: [],
+  cancelled: [],
+};
+
+/**
+ * Validate that an order has at least one item.
+ * Throws if the items array is empty.
+ */
+export function validateOrderHasItems(items: OrderItem[]): void {
+  if (items.length === 0) {
+    throw new Error('Order must have at least one item');
+  }
+}
+
+/**
+ * Validate that an order exists.
+ * Throws if the order is undefined.
+ */
+export function validateOrderExists(id: string, order: Order | undefined): void {
+  if (!order) {
+    throw new Error(`Order not found: ${id}`);
+  }
+}
+
+/**
+ * Check whether a status transition is valid.
+ */
+export function isValidStatusTransition(from: OrderStatus, to: OrderStatus): boolean {
+  return ORDER_STATUS_TRANSITIONS[from].includes(to);
+}
+
+/**
+ * Validate a status transition, throwing if it is not allowed.
+ */
+export function validateStatusTransition(from: OrderStatus, to: OrderStatus): void {
+  if (!isValidStatusTransition(from, to)) {
+    throw new Error(`Invalid status transition: ${from} -> ${to}`);
+  }
+}

